@ARTICLE{10.1096/fj.202504725R,
	author = {Wang Y(1) and Edin ML(2) and Jing N(1) and Lih FB(2) and Yang J(3) and Yeliseyev V(4) and Zeldin DC(2) and Zhang G(1)(5).},
	title = {Gut Microbiota Modulate Adipose Eicosanoid Metabolism: Potential Roles of the Lipoxygenase Pathway.},
	journal = {FASEB J},
	year = {2026},
	abstract = {Numerous studies support that gut microbiota regulate adipose inflammation and function, thereby influencing the development of obesity, diabetes, and associated metabolic disorders; however, the underlying mechanisms remain not fully elucidated. While previous studies on microbiota-adipose interactions have primarily focused on how gut microbiota modulate adipose protein-based mediators, the role of lipid mediators (LMs), lipid-based signaling molecules crucial for adipose homeostasis, remains unclear. In this study, we used high-performance liquid chromatography-tandem mass spectrometry (LC-MS/MS)-based targeted lipidomics, which can quantify over 100 LMs, to compare LM profiles in adipose tissues from germ-free (GF) and conventionally raised (specific pathogen-free, SPF) mice. We found that 5- and 12/15-lipoxygenase (LOX)-derived LMs were among the most significantly altered metabolites in conventionally raised mice compared to GF controls. Mechanistically, the effects of the gut microbiota are associated with two potential pathways: (1) downregulating transcriptional expression of 5- and 12/15-LOX in adipose tissue, and (2) lowering circulating levels of 5- and 12/15-LOX-derived metabolites. Given the potent biological activities of LOX-derived LMs, these findings may suggest a novel mechanism by which gut microbiota modulate adipose function and influence disease development.},
	doi = {10.1096/fj.202504725R},
	pmid = {41733824 [Indexed for MEDLINE]}
}

@ARTICLE{10.1039/d5fo05239d,
	author = {Jing N(1)(2) and Mu T(1)(2) and Bian X(1) and Zhao H(3) and Li Q(3) and Chen Z(3) and Tang H(1) and Li J(1) and Guo J(3) and Zhao K(1).},
	title = {Fu brick tea extracts attenuate HFD induced lipid deposition by regulating the glycerolipid metabolism of gut microbiota and adipose tissue.},
	journal = {Food Funct},
	year = {2026},
	abstract = {Fu brick tea (FT), known for regulating lipid metabolism, was studied to explore its lipid-lowering mechanism by analyzing its effects on gut microbes and adipose tissue. Mice were given chow, high-fat diet (HFD), or HFD + FT aqueous extract (FTE, 400 mg per kg BW). FTE reduced HFD-induced fat deposition, altered gut microbiota (enriched the "glycerolipid metabolism" pathway, reversed HFD-suppressed Firmicutes_bacterium_ASF500), and affected epididymal fat transcriptome (genes enriched in PPAR, glycerolipid/fatty acid metabolism). Four lipid-related genes (Lipf, Lep, Kdsr, Esrra) showed reversed expression patterns, while FTE treatment demonstrated no significant in vitro effects on adipocyte differentiation. FTE may exert lipid-lowering effects via regulating gut microbe/adipose glycerolipid metabolism, with downstream metabolites playing a key role. In summary, FTE may alleviate lipid deposition by elevating Firmicutes_bacterium_ASF500 to regulate dietary derived metabolites, which may enhance Esrra-mediated fatty acid oxidation-related gene expression, thereby improving triglyceride metabolism. Further studies are warranted to elucidate the specific roles and interactions of FTE's potential microbial and gene targets.},
	doi = {10.1039/d5fo05239d},
	pmid = {41729608 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.jacl.2025.06.016,
	author = {McNaught J(1).},
	title = {Pathophysiology of obesity.},
	journal = {J Clin Lipidol},
	year = {2026},
	abstract = {BACKGROUND: Obesity is an increasingly common, multifactorial condition with significant consequences for patients and the healthcare system. Obesity represents a major modifiable risk factor for cardiovascular disease, type 2 diabetes and metabolic syndrome. Understanding of the pathways and mechanisms involved in the development of obesity will allow for further advancement in treatment modalities. SOURCES OF MATERIAL: Evidence was drawn from current peer-reviewed literature addressing the pathophysiology of obesity identified via PubMed searches. ABSTRACT OF FINDINGS: Obesity results from impaired energy homeostasis and chronic positive energy balance. The etiology of the positive energy balance is often a complex interplay of genetic, environmental, neurohormonal, and psychosocial factors. This paper discusses the pathophysiology of obesity. Topics included in this discussion are the genetics of obesity, the process of energy regulation and metabolism of adipose tissue. Also discussed is how visceral obesity is especially harmful, as it promotes insulin resistance, altered lipid metabolism, and inflammation. CONCLUSION: Understanding the underlying pathophysiology of obesity is crucial for making advances in treating this condition with a more individualized approach.},
	doi = {10.1016/j.jacl.2025.06.016},
	pmid = {41708211 [Indexed for MEDLINE]}
}

@ARTICLE{10.2337/db25-0979,
	author = {Lin S(1) and Lytle KA(1) and Fink N(2) and Jensen MD(1).},
	title = {Adipose Tissue Resistance to the Antilipolytic Effect of Insulin and Niacin in Humans With Obesity.},
	journal = {Diabetes},
	year = {2026},
	abstract = {Adipose tissue (AT) lipolysis insulin resistance results in excess free fatty acid (FFA) release. We tested the hypothesis that the ability of insulin to suppress AT lipolysis is unrelated to the ability of niacin to suppress lipolysis, because niacin acts through a different proximal signaling pathway. Ten volunteers (5 women and 5 men) with upper-body obesity and/or type 2 diabetes mellitus (T2DM) underwent two study visits with overnight intravenous infusions of niacin (1.4 mg/min) or saline, followed by a hyperinsulinemic-euglycemic clamp. FFA-palmitate Ra was measured using [U-13C] and [2H9]palmitate infusions; abdominal AT biopsies were performed before and during the insulin clamp. The suppression of FFA-palmitate Ra by insulin on the saline control day and by niacin after an overnight infusion were highly correlated (r = -0.93, P < 0.001). Fasting AT Akt (pAktS473/474-to-panAkt ratio, P = 0.01) and perilipin 1 (PLN1) (pPLN1S552-to-panPLN1 ratio, P = 0.02) phosphorylation were less during niacin treatment than in the saline control study. Because the suppression of lipolysis by insulin and niacin are highly correlated within individuals and because niacin and insulin act through different proximal signaling pathways, we propose dysregulated AT lipolysis in obesity/T2DM is due to dysfunction(s) in distal lipolysis proteins rather than isolated "insulin resistance." ARTICLE HIGHLIGHTS: We undertook this study to compare adipose tissue lipolysis responses to insulin and niacin in humans. We tested the hypothesis that adipose tissue insulin resistance would be unrelated to adipose tissue niacin resistance. The suppression of lipolysis by insulin and niacin were highly correlated. Dysregulated adipose tissue lipolysis in obesity/type 2 diabetes is due to dysfunction(s) in distal lipolysis proteins rather than isolated "insulin resistance."},
	doi = {10.2337/db25-0979},
	pmid = {41701570 [Indexed for MEDLINE]}
}

